def rle(s):
    if not s: return ''

    result = []
    prev_char, count = s[0], 1

    for char in s[1:]:
        if char == prev_char:
            count += 1
        else:
            result.append(f'{prev_char}{count}')
            prev_char, count = char, 1

    result.append(f'{prev_char}{count}')

    return ''.join(result)
